const item = $input.first();
const execution = item.json.execution || {};
const workflow = item.json.workflow || {};

const workflowName = workflow.name || 'Inconnu';
const errorMessage = execution.error?.message || 'Erreur inconnue';
const errorNode = execution.lastNodeExecuted || 'N/A';
const executionId = execution.id || '';
const startedAt = execution.startedAt ? new Date(execution.startedAt).toLocaleString('fr-FR') : 'N/A';
const mode = execution.mode || 'N/A';
const retryUrl = execution.url || '';

const html = `<div style="font-family: Helvetica, Arial, sans-serif; font-size: 12pt; color: #333; line-height: 1.6; max-width: 600px;">
  <p style="font-size: 14pt; font-weight: bold; color: #e74c3c;">Erreur workflow</p>
  <table style="border-collapse: collapse; width: 100%; margin: 16px 0;">
    <tr><td style="padding: 8px; font-weight: bold; border-bottom: 1px solid #eee; width: 140px;">Workflow</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${workflowName}</td></tr>
    <tr><td style="padding: 8px; font-weight: bold; border-bottom: 1px solid #eee;">Node en erreur</td><td style="padding: 8px; border-bottom: 1px solid #eee; color: #e74c3c; font-weight: bold;">${errorNode}</td></tr>
    <tr><td style="padding: 8px; font-weight: bold; border-bottom: 1px solid #eee;">Message</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${errorMessage}</td></tr>
    <tr><td style="padding: 8px; font-weight: bold; border-bottom: 1px solid #eee;">Date</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${startedAt}</td></tr>
    <tr><td style="padding: 8px; font-weight: bold; border-bottom: 1px solid #eee;">Mode</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${mode}</td></tr>
    <tr><td style="padding: 8px; font-weight: bold;">Execution ID</td><td style="padding: 8px;">${executionId}</td></tr>
  </table>
  ${retryUrl ? '<p><a href="' + retryUrl + '" style="color: #3498db;">Voir l\'exécution dans n8n</a></p>' : ''}
</div>`;

return [{
  json: {
    sujet: '[ERREUR] ' + workflowName + ' — ' + errorNode,
    corps: html
  }
}];
